// Rescatamos los IDs usando .first() como pide n8n
const ids = $('Code procesar pendientes').first().json.idsActualizar;

// Convertimos esa lista en "Items" individuales que n8n pueda procesar
return ids.map(id => {
  return { 
    json: { ID_Gasto: id } 
  };
});

try {
  // 1. Verificamos si el nodo de Gemini falló y trajo un error de API
  if ($input.first().json.error || !$input.first().json.content) {
    throw new Error("Falla en la API de Gemini");
  }

  // 2. Extraemos y parseamos los datos
  const rawText = $input.first().json.content.parts[0].text;
  const data = JSON.parse(rawText);

  // Si el usuario envió un saludo ("no_financiero"), lo pasamos tal cual
  if (data.error) {
     return [{ json: data }];
  }

  // 3. Generamos datos de control para la base de datos
  data.id = Date.now().toString(); 
  data.fecha = new Date().toLocaleString("es-VE", { timeZone: "America/Caracas" }); 
  data.estado = "Pendiente";

  return [{ json: data }];

} catch (e) {
  // 4. EL ESCUDO: Si la API falla o el JSON es inválido, atrapamos el error
  const textoOriginal = $('Telegram Trigger').first().json.message.text;

  return [{ 
    json: { 
      error: "api_falla", 
      texto_original: textoOriginal 
    } 
  }];
}

// 1. Obtenemos todas las filas que encontró Google Sheets
const items = $input.all();
const transacciones = [];
const idsActualizar = []; // Guardaremos los IDs para marcarlos como "Guardados" más adelante

// 2. Recorremos cada fila para armar los objetos
for (const item of items) {
  const fila = item.json;

  // Armamos el objeto base asegurando que el monto sea un string (como pide Cashew)
  let gasto = {
    amount: fila.Monto.toString(),
    title: fila.Titulo
  };

  // Agregamos las categorías y cuentas solo si la celda no está vacía
  if (fila.Categoria) gasto.category = fila.Categoria;
  if (fila.Subcategoria) gasto.subcategory = fila.Subcategoria;
  if (fila.Cuenta) gasto.account = fila.Cuenta;

  transacciones.push(gasto);
  idsActualizar.push(fila.ID); 
}

// 3. Armamos el objeto maestro JSON con el arreglo "transactions"
const payload = {
  transactions: transacciones
};

// 4. Codificamos el JSON completo a formato URL
const jsonString = JSON.stringify(payload);
const encodedJSON = encodeURIComponent(jsonString);

// 5. Construimos el App Link final
const deepLink = `https://cashewapp.web.app/addTransaction?JSON=${encodedJSON}`;

// 6. Devolvemos un ÚNICO paquete de datos al siguiente nodo
return [{
  json: {
    deepLink: deepLink,
    cantidad: transacciones.length,
    idsActualizar: idsActualizar
  }
}];

const items = $input.all();
let mensaje = "📝 <b>Tus transacciones pendientes:</b>\n\n";
let contador = 0;

for (const item of items) {
  const fila = item.json;

  // Verificamos que la fila tenga datos reales
  if(fila.ID) { 
    contador++;
    mensaje += `🔸 <b>${fila.Titulo}</b>: ${fila.Monto}\n`;

    // Agregamos categoría si existe
    if(fila.Categoria) {
      let sub = fila.Subcategoria ? ` ➡️ ${fila.Subcategoria}` : '';
      mensaje += `   └ <i>${fila.Categoria}${sub}</i>\n`;
    }
    // Agregamos cuenta si existe
    if(fila.Cuenta) {
      mensaje += `   └ 🏦 <i>${fila.Cuenta}</i>\n`;
    }
    mensaje += "\n"; 
  }
}

mensaje += `Total: <b>${contador}</b> registro(s) esperando.\n`;
mensaje += `👉 Usa /guardar_dia para enviarlos a Cashew.`;

return [{
  json: { textoFormateado: mensaje }
}];

const cuentas = $json.Cuentas || "No definidas";
const estructuraJSON = $json.Estructura_JSON;
let resumenVisual = "";

if (estructuraJSON && estructuraJSON.trim() !== "") {
  try {
    const arbol = JSON.parse(estructuraJSON);
    for (const [cat, subs] of Object.entries(arbol)) {
      resumenVisual += `\n📁 <b>${cat}</b>`;
      if (subs.length > 0) resumenVisual += `\n   └ <i>${subs.join(', ')}</i>`;
    }
  } catch (e) { resumenVisual = "\n⚠️ Error leyendo categorías."; }
} else { resumenVisual = "\nNo tienes categorías configuradas."; }

let mensajeFinal = `👤 <b>TU PERFIL DE CASHEWBOT</b>\n\n🏦 <b>Tus Cuentas:</b>\n${cuentas}\n\n🌳 <b>Tu Árbol de Categorías:</b>${resumenVisual}\n\n👉 <i>Si necesitas modificar algo, usa /reiniciar_perfil</i>`;

return [{ json: { textoPerfil: mensajeFinal } }];

try {
  const textoUsuario = $('Telegram Trigger').first().json.message.text;
  const cashewData = JSON.parse(textoUsuario);

  const cuentasUnidas = cashewData.accounts.join(', ');
  const arbolCategorias = JSON.stringify(cashewData.categories);

  return [{
    json: {
      exito: true,
      cuentasFinales: cuentasUnidas,
      estructuraFinal: arbolCategorias
    }
  }];

} catch (error) {
  return [{
    json: {
      exito: false,
      mensaje: "⚠️ Error: El texto que enviaste no parece ser la configuración correcta. Asegúrate de copiar el texto exacto desde Cashew y vuelve a pegarlo."
    }
  }];
}
